import dspy
import vex

class IOCClassifier(dspy.Signature):
    IOC = dspy.InputField()
    classification = dspy.OutputField()

@vex.verify(
    assertions=[
        lambda example: 'IP:' not in example.classification,
        lambda example: 'SHA256:' not in example.classification
    ]
)
def classify_threat(example):
    module = IOCClassifier()
    return module(**example)

# Usage
prediction = classify_threat({'IOC': '8.8.8.8'})

import dspy
import vex
import requests

def verify_cve(cve_id):
    url = f'https://services.nvd.nist.gov/rest/json/cves/2.0?cveId={cve_id}'
    resp = requests.get(url)
    return resp.status_code == 200

class VulnerabilityAssessor(dspy.Signature):
    symptoms = dspy.InputField()
    cve_id = dspy.OutputField()

@vex.verify(
    assertions=[
        lambda ex: verify_cve(ex.cve_id),
        "cve_id.startswith('CVE-')"
    ],
    timeout=5000
)
def assess_vulnerability(symptoms):
    module = VulnerabilityAssessor()
    return module(symptoms=symptoms)

# Usage
assessment = assess_vulnerability({'symptoms': 'buffer overflow in nginx'})
